     1|/**
     2| * Investor-first home feed — mixed layout per approved P0 design:
     3| *   3 regular investment cards (compact, horizontal gallery, metrics)
     4| *   followed by 1 featured project video reel.
     5| *
     6| * Regular cards use TrustDealCard. Reels use CanonicalInvestmentReelCard.
     7| * This is the Main/Home module, not the Reels module.
     8| */
     9|import React, { Component, useCallback, useMemo, type ReactNode } from 'react';
    10|import { View, Text, StyleSheet, ActivityIndicator, TouchableOpacity, useWindowDimensions } from 'react-native';
    11|import { Share } from 'react-native';
    12|import { useRouter } from 'expo-router';
    13|import { useQuery } from '@tanstack/react-query';
    14|import { Landmark, Sparkles, TrendingUp } from 'lucide-react-native';
    15|import Colors from '@/constants/colors';
    16|import CanonicalInvestmentReelCard, {
    17|  feedVideoToReelData,
    18|  type CanonicalReelData,
    19|} from '@/components/CanonicalInvestmentReelCard';
    20|import TrustDealCard from '@/components/TrustDealCard';
    21|import { fetchHomeFeed, type HomeFeedBlock, type HomeFeedDeal, type FeedVideo } from '@/lib/video-feed';
    22|import { parseDeal } from '@/lib/parse-deal';
    23|import type { ParsedJVDeal } from '@/lib/parse-deal';
    24|import type { JVAgreement } from '@/types/jv';
    25|import { toggleProjectLike, trackProjectShare } from '@/lib/project-engagement';
    26|import { toggleVideoSave, getViewerId, buildVideoShareUrl } from '@/lib/video-platform';
    27|import { CANONICAL_MIN_INVESTMENT } from '@/lib/published-deal-card-model';
    28|
    29|/** Per-card error boundary so one bad reel never crashes the home feed */
    30|class VideoCardBoundary extends Component<{ children: ReactNode }, { hasError: boolean }> {
    31|  state = { hasError: false };
    32|  static getDerivedStateFromError() { return { hasError: true }; }
    33|  componentDidCatch(err: Error) { console.warn('[InvestorFirstFeed] Card crashed:', err.message); }
    34|  render() {
    35|    if (this.state.hasError) {
    36|      return (
    37|        <View style={{ padding: 20, alignItems: 'center' }}>
    38|          <Text style={{ color: Colors.textSecondary, fontSize: 13 }}>Content temporarily unavailable</Text>
    39|        </View>
    40|      );
    41|    }
    42|    return this.props.children as React.ReactElement;
    43|  }
    44|}
    45|
    46|export default function InvestorFirstFeed({ jvDeals, jvDealsLoading, isXs, cardWidth, openQuickBuy }: {
    47|  jvDeals: JVAgreement[];
    48|  jvDealsLoading: boolean;
    49|  isXs: boolean;
    50|  cardWidth: number;
    51|  openQuickBuy: (deal: JVAgreement) => void;
    52|}) {
    53|  const router = useRouter();
    54|  const { width: screenWidth } = useWindowDimensions();
    55|  const [muted, setMuted] = React.useState<boolean>(true);
    56|  const padH = isXs ? 16 : 20;
    57|  const feedHeight = Math.min(screenWidth - padH * 2, 520);
    58|
    59|  const homeFeedQuery = useQuery({
    60|    queryKey: ['ivx-home-feed'],
    61|    queryFn: () => fetchHomeFeed(60),
    62|    retry: 1,
    63|    staleTime: 1000 * 60 * 2,
    64|    refetchOnWindowFocus: false,
    65|  });
    66|
    67|  const localById = useMemo(() => {
    68|    const map = new Map<string, JVAgreement>();
    69|    for (const d of jvDeals) if (d?.id) map.set(String(d.id), d);
    70|    return map;
    71|  }, [jvDeals]);
    72|
    73|  /** Maps a HomeFeedDeal to a ParsedJVDeal for TrustDealCard rendering. */
    74|  const homeFeedDealToParsed = useCallback((deal: HomeFeedDeal): ParsedJVDeal | null => {
    75|    const local = localById.get(deal.id);
    76|    if (local) return local as unknown as ParsedJVDeal;
    77|    return parseDeal({
    78|      id: deal.id,
    79|      title: deal.name || undefined,
    80|      projectName: deal.name || undefined,
    81|      propertyAddress: deal.city || undefined,
    82|      status: deal.status || undefined,
    83|      type: deal.deal_type || undefined,
    84|      totalInvestment: deal.investment_amount || undefined,
    85|      expectedROI: deal.expected_roi ? Number(deal.expected_roi) : undefined,
    86|      minInvestment: deal.min_investment ?? CANONICAL_MIN_INVESTMENT,
    87|      publishedAt: deal.created_at || undefined,
    88|      created_at: deal.created_at || undefined,
    89|      photos: deal.photo_url ? [deal.photo_url] : undefined,
    90|    } as Record<string, unknown>);
    91|  }, [localById]);
    92|
    93|  /** Canonical blocks from the backend; local-only fallback keeps the page alive offline. */
    94|  const blocks = useMemo<HomeFeedBlock[]>(() => {
    95|    const remote = homeFeedQuery.data?.blocks ?? [];
    96|    if (remote.length > 0) return remote;
    97|    return jvDeals.map((d, i): HomeFeedBlock => ({
    98|      position: i,
    99|      type: 'deal' as const,
   100|      display_type: 'investment_card' as const,
   101|      deal: {
   102|        id: String(d.id),
   103|        name: d.projectName || d.title || null,
   104|        city: d.propertyAddress ?? null,
   105|        phase: null,
   106|        status: d.status ?? null,
   107|        deal_type: d.type ?? null,
   108|        investment_amount: d.totalInvestment ?? null,
   109|        expected_roi: d.expectedROI != null ? String(d.expectedROI) : null,
   110|        min_investment: null,
   111|        progress_percent: null,
   112|        photo_url: null,
   113|        url: `https://ivxholding.com/?deal=${d.id}#deals`,
   114|        is_featured: false,
   115|        priority: 0,
   116|        display_order: null,
   117|        created_at: d.createdAt ?? null,
   118|      },
   119|    }));
   120|  }, [homeFeedQuery.data?.blocks, jvDeals]);
   121|
   122|  /** Mixed-feed layout: first 3 deal blocks become regular cards, next video block is a reel. */
   123|  const visibleBlocks = useMemo(() => {
   124|    const regular: HomeFeedBlock[] = [];
   125|    const reels: HomeFeedBlock[] = [];
   126|    for (const b of blocks) {
   127|      if (b.type === 'deal') {
   128|        if (regular.length < 3) regular.push(b);
   129|        else reels.push(b);
   130|      } else if (b.type === 'video') {
   131|        reels.push(b);
   132|      }
   133|    }
   134|    const regularDeals = regular.filter((b): b is { position: number; type: 'deal'; display_type: 'investment_card'; deal: HomeFeedDeal } => b.type === 'deal');
   135|    const videoReels = reels.filter((b): b is { position: number; type: 'video'; display_type: 'reel'; video: FeedVideo } => b.type === 'video');
   136|    return { regular: regularDeals, reels: videoReels };
   137|  }, [blocks]);
   138|
   139|  const goToDeal = useCallback((dealId: string) => {
   140|    router.push({ pathname: '/jv-invest', params: { jvId: dealId } } as any);
   141|  }, [router]);
   142|
   143|  const handleReelLike = useCallback(async (data: CanonicalReelData) => {
   144|    const id = data.dealId ?? data.reelId;
   145|    void toggleProjectLike(id, null).catch(() => {});
   146|  }, []);
   147|
   148|  const handleReelSave = useCallback(async (data: CanonicalReelData) => {
   149|    const viewerId = await getViewerId().catch(() => null);
   150|    void toggleVideoSave(data.reelId, viewerId).catch(() => {});
   151|  }, []);
   152|
   153|  const handleReelShare = useCallback(async (data: CanonicalReelData) => {
   154|    const url = data.dealUrl ?? buildVideoShareUrl(data.reelId);
   155|    try {
   156|      await Share.share({ message: `${data.title} — ${url}` });
   157|      void trackProjectShare(data.reelId, 'social', null);
   158|    } catch {}
   159|  }, []);
   160|
   161|  const handleReelComment = useCallback((data: CanonicalReelData) => {
   162|    router.push({ pathname: '/videos', params: { type: 'reel', focus: data.reelId } } as any);
   163|  }, [router]);
   164|
   165|  const isLoading = (homeFeedQuery.isLoading && jvDealsLoading) || (homeFeedQuery.isLoading && blocks.length === 0);
   166|
   167|  return (
   168|    <View style={styles.section}>
   169|      <View style={[styles.header, { paddingHorizontal: padH }]}>
   170|        <View style={styles.titleRow}>
   171|          <Sparkles size={isXs ? 16 : 18} color={Colors.primary} />
   172|          <Text style={[styles.title, { fontSize: isXs ? 16 : 18 }]}>Featured Deals</Text>
   173|        </View>
   174|        <View style={styles.liveBadge}>
   175|          <TrendingUp size={11} color={Colors.success} />
   176|          <Text style={styles.liveBadgeText}>Investor First</Text>
   177|        </View>
   178|      </View>
   179|
   180|      {isLoading ? (
   181|        <View style={[styles.loadingBox, { marginHorizontal: padH }]}>
   182|          <ActivityIndicator size="large" color={Colors.primary} />
   183|          <Text style={styles.loadingText}>Syncing live deals...</Text>
   184|        </View>
   185|      ) : blocks.length === 0 ? (
   186|        <View style={styles.emptyBox}>
   187|          <Landmark size={32} color={Colors.textTertiary} />
   188|          <Text style={styles.emptyTitle}>No deals available yet</Text>
   189|          <Text style={styles.emptySubtitle}>Check back soon for new opportunities</Text>
   190|        </View>
   191|      ) : (
   192|        <View style={{ paddingHorizontal: padH, gap: 14 }}>
   193|          {visibleBlocks.regular.map((block) => {
   194|            const parsed = homeFeedDealToParsed(block.deal);
   195|            if (!parsed) return null;
   196|            return (
   197|              <TrustDealCard
   198|                key={`regular-deal-${block.deal.id}`}
   199|                deal={parsed}
   200|                onInvestNow={() => openQuickBuy(parsed as unknown as JVAgreement)}
   201|                onViewDetails={() => goToDeal(block.deal.id)}
   202|                galleryWidth={cardWidth - 32}
   203|              />
   204|            );
   205|          })}
   206|          {visibleBlocks.reels.slice(0, 1).map((block) => {
   207|            if (block.type !== 'video') return null;
   208|            const reelData = feedVideoToReelData(block.video);
   209|            return (
   210|              <VideoCardBoundary key={`video-${block.video.id}`}>
   211|                <CanonicalInvestmentReelCard
   212|                  data={reelData}
   213|                  mode="feed"
   214|                  isActive={false}
   215|                  shouldMountVideo={false}
   216|                  isMuted={muted}
   217|                  feedHeight={feedHeight}
   218|                  onToggleMute={() => setMuted(m => !m)}
   219|                  onLike={handleReelLike}
   220|                  onComment={handleReelComment}
   221|                  onSave={handleReelSave}
   222|                  onShare={handleReelShare}
   223|                  onOpenDeal={(d) => goToDeal(d.dealId ?? d.reelId)}
   224|                  onInvest={(d) => goToDeal(d.dealId ?? d.reelId)}
   225|                  testIDPrefix="home-reel"
   226|                />
   227|              </VideoCardBoundary>
   228|            );
   229|          })}
   230|          {visibleBlocks.reels.length > 1 && (
   231|            <View style={styles.moreReelsHint}>
   232|              <TouchableOpacity onPress={() => router.push('/videos')}>
   233|                <Text style={styles.moreReelsHintText}>More reels in IVX Reels</Text>
   234|              </TouchableOpacity>
   235|            </View>
   236|          )}
   237|        </View>
   238|      )}
   239|    </View>
   240|  );
   241|}
   242|
   243|const styles = StyleSheet.create({
   244|  section: {
   245|    marginBottom: 20,
   246|  },
   247|  header: {
   248|    flexDirection: 'row',
   249|    justifyContent: 'space-between',
   250|    alignItems: 'center',
   251|    marginBottom: 14,
   252|  },
