export async function fetchHomeFeed(limit = 60): Promise<HomeFeedResponse> {
  const res = await fetch(`${API_BASE}/api/ivx/video-platform/home-feed?limit=${limit}`);
  if (!res.ok) {
    throw new Error(`Home feed request failed (${res.status})`);
  }
