  return {
    pattern: data.pattern ?? '',
    ordering: data.ordering ?? '',
    blocks: Array.isArray(data.blocks) ? data.blocks : [],
    deal_count: data.deal_count ?? 0,
    video_count: data.video_count ?? 0,
  };
}

